                        <span className="w-2 h-2 rounded-full bg-green-500 mr-1"></span> Available
                    </div>
                    <div className="flex items-center text-gray-500 dark:text-gray-400">
                        <span className="w-2 h-2 rounded-full bg-red-500 mr-1"></span> In Use
                    </div>
