                            {room.isActive ? (
                                <div className="flex items-center text-[10px] font-black text-red-600 dark:text-red-400">
                                    <LivePulse /> LIVE
                                </div>
                            ) : (
                                <span className="text-[10px] font-bold text-green-600 dark:text-green-500 bg-green-100 dark:bg-green-900/30 px-1.5 py-0.5 rounded uppercase">Available</span>
                            )}
                        </div>

                        {room.isActive && room.vc ? (
                            <div className="space-y-2 animate-fadeIn">
                                <p className="text-xs text-gray-600 dark:text-gray-300 font-medium line-clamp-1 italic">
                                    "{room.vc.subject}"
                                </p>
                                <div className="pt-2 border-t border-red-100 dark:border-red-900/30">
                                    <p className="text-[10px] uppercase text-gray-500 mb-1">Conductor</p>
                                    <ContactSticker label="VC" userId={room.vc.conductorId} />
                                </div>
