const LoginScreen: React.FC = () => {
  const [selectedRole, setSelectedRole] = useState<UserRole | ''>('');
  const [selectedUser, setSelectedUser] = useState<string>('');
  const [password, setPassword] = useState('');
  const { users, login, theme } = useAppContext();
  const navigate = useNavigate();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedUser && password) {
      const success = login(selectedUser, password);
      if (success) {
        navigate('/dashboard');
      }
    }
  };

  const usersInRole = useMemo(() => {
    if (!selectedRole) return [];
    return users.filter(user => user.role === selectedRole);
  }, [selectedRole, users]);

  const handleRoleChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setSelectedRole(e.target.value as UserRole);
    setSelectedUser(''); 
    setPassword('');
  };

  return (
    <div className="flex flex-col md:flex-row min-h-screen overflow-hidden bg-white dark:bg-slate-900 transition-colors duration-300">

      {/* Cartoonish Background Elements */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden">
          <div className="absolute top-[-5%] left-[-5%] w-64 h-64 bg-cyan-400/20 rounded-full blur-3xl animate-blob"></div>
          <div className="absolute bottom-[-5%] right-[-5%] w-96 h-96 bg-lime-400/20 rounded-full blur-3xl animate-blob animation-delay-2000"></div>
          <div className="absolute top-1/2 left-1/4 w-48 h-48 bg-purple-400/10 rounded-full blur-3xl animate-blob animation-delay-4000"></div>
      </div>

