          <h2 className="text-5xl font-black text-slate-900 dark:text-white mb-4 text-center leading-tight">
            Connect <br />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-cyan-600 to-lime-600">Instantly.</span>
          </h2>
          <p className="text-xl text-slate-600 dark:text-slate-400 text-center max-w-sm font-medium italic">
            The modern Video Conference bridge for Coal India Limited.
          </p>
          <div className="mt-8 transform -rotate-2">
             <CartoonIllustration />
          </div>
      </div>

      {/* Login Form Section */}
      <div className="flex-1 flex items-center justify-center p-6 md:p-12 z-20">
        <div className="w-full max-w-md bg-white dark:bg-slate-800 border-4 border-black p-8 rounded-3xl shadow-[12px_12px_0px_0px_rgba(0,0,0,1)] dark:shadow-[12px_12px_0px_0px_rgba(255,255,255,0.1)] transform hover:-translate-y-1 transition-transform">

          <div className="md:hidden flex justify-center mb-6">
             <Logo className="w-20 h-20 drop-shadow-[4px_4px_0px_rgba(0,0,0,1)]" />
          </div>

          <h2 className="text-4xl font-black text-gray-900 dark:text-white mb-2 text-center">Hello! 👋</h2>
          <p className="text-center text-gray-500 dark:text-gray-400 font-bold mb-8 uppercase tracking-widest text-xs">Secure Portal Login</p>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="group">
              <label htmlFor="role" className="block text-sm font-black text-gray-700 dark:text-gray-300 mb-2 uppercase tracking-wide">
                Select Role
              </label>
              <select
                id="role"
                value={selectedRole}
                onChange={handleRoleChange}
                className="w-full p-4 bg-white dark:bg-slate-700 text-gray-900 dark:text-white border-4 border-black rounded-2xl focus:ring-0 focus:shadow-[6px_6px_0px_0px_rgba(8,145,178,1)] transition-all font-bold cursor-pointer"
              >
                <option value="" disabled>Choose your role...</option>
                {Object.values(UserRole).map(role => (
                  <option key={role} value={role}>{role}</option>
                ))}
              </select>
            </div>

            {selectedRole && (
              <div className="animate-fade-in-down">
                <label htmlFor="user" className="block text-sm font-black text-gray-700 dark:text-gray-300 mb-2 uppercase tracking-wide">
                  Select Account
                </label>
                <select
                  id="user"
                  value={selectedUser}
                  onChange={e => setSelectedUser(e.target.value)}
                  className="w-full p-4 bg-white dark:bg-slate-700 text-gray-900 dark:text-white border-4 border-black rounded-2xl focus:ring-0 focus:shadow-[6px_6px_0px_0px_rgba(101,163,13,1)] transition-all font-bold cursor-pointer"
                >
                  <option value="" disabled>Find your name...</option>
                  {usersInRole.map(user => (
                    <option key={user.id} value={user.id}>
                      {user.name}
                      {user.status === UserStatus.Pending ? ' (🕒 Pending)' : ''}
