          <div className="mt-10 pt-6 border-t-4 border-dashed border-black">
             <p className="text-center font-bold text-gray-600 dark:text-gray-400">
                New to CIL VC?{' '}
                <Link to="/signup" className="text-cyan-600 dark:text-cyan-400 hover:underline decoration-4 underline-offset-4">
                  Register Account
                </Link>
             </p>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes blob {
          0% { transform: translate(0px, 0px) scale(1); }
          33% { transform: translate(30px, -50px) scale(1.1); }
          66% { transform: translate(-20px, 20px) scale(0.9); }
          100% { transform: translate(0px, 0px) scale(1); }
        }
        .animate-blob {
          animation: blob 7s infinite;
        }
        .animation-delay-2000 {
          animation-delay: 2s;
        }
        .animation-delay-4000 {
          animation-delay: 4s;
        }
        .animate-fade-in-down {
            animation: fadeInDown 0.4s ease-out;
        }
        @keyframes fadeInDown {
            from { opacity: 0; transform: translateY(-10px); }
            to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
