import { GoogleGenAI } from "@google/genai";
import { VC, User } from '../types';

// The API key MUST be obtained exclusively from the environment variable `process.env.API_KEY`.
// This variable is assumed to be pre-configured and accessible.
const apiKey = process.env.API_KEY;

// Initialize AI client only if API key is available to prevent app crash on load.
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

if (!ai) {
    console.error("API_KEY environment variable not set. AI report generation will be disabled.");
}

export const generateVCReport = async (vcs: VC[], users: User[]): Promise<string> => {
    if (!ai) {
        return "AI report generation is disabled because the API key is not configured.";
    }

    const getUserName = (userId: string) => users.find(u => u.id === userId)?.name || 'Unknown';

    const prompt = `
        Generate a concise summary report based on the following VC (Video Conference) data.
        The data is provided in JSON format.
        Analyze the data and provide insights on VC statuses (Scheduled, Completed, In Progress, Cancelled),
        and any other notable patterns. Do not just list the meetings. Provide a high-level summary.

        VC Data:
        ${JSON.stringify(vcs.map(vc => ({
            subject: vc.subject,
            status: vc.status,
            manager: getUserName(vc.managerId),
            conductor: getUserName(vc.conductorId),
            startTime: vc.startTime,
            remarks: vc.remarks,
        })), null, 2)}
    `;

    try {
        // Fix: Use 'gemini-3-flash-preview' for basic text tasks like summarization
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });

        return response.text;
    } catch (error) {
        console.error("Error generating report from Gemini API:", error);
        return "Failed to generate report due to an API error.";
    }
};

import { GoogleGenAI, Type } from "@google/genai";

const apiKey = process.env.API_KEY;
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

export interface WebexParsedDetails {
    subject: string;
    startTime: string; // ISO String
    link: string;
    webexId: string;
}

export const parseWebexInvite = async (inviteText: string): Promise<WebexParsedDetails | null> => {
    if (!ai) {
        console.error("Gemini API not configured for Webex parsing.");
        return null;
    }

    const prompt = `
        You are a specialized parser for Cisco Webex meeting invitations.
        Extract the following information from the text below and return it as a JSON object.
        - subject: The title or topic of the meeting.
        - startTime: The scheduled start date and time. Convert this to an ISO 8601 string. Use the current year (${new Date().getFullYear()}) if not specified.
        - link: The direct Webex join URL.
        - webexId: The meeting number or ID.

        If a field is missing, use an empty string.

        Invitation Text:
        """
        ${inviteText}
        """
    `;

    try {
        // Fix: Use 'gemini-3-pro-preview' for complex text reasoning/parsing tasks
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt,
            config: {
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        subject: { type: Type.STRING },
                        startTime: { type: Type.STRING },
                        link: { type: Type.STRING },
                        webexId: { type: Type.STRING },
                    },
                    required: ['subject', 'startTime', 'link', 'webexId']
                }
            }
        });

        const result = JSON.parse(response.text || '{}');
        return result as WebexParsedDetails;
    } catch (error) {
        console.error("Error parsing Webex invite:", error);
        return null;
    }
};

