              </div>
              <Card className="!p-0 overflow-hidden">
                  <div className="overflow-x-auto">
                      <table className="w-full text-left">
                          <thead className="bg-slate-50 dark:bg-slate-800/50">
                              <tr>
                                  <th className="p-4 text-[10px] font-black uppercase tracking-widest text-slate-500">Personnel</th>
                                  <th className="p-4 text-[10px] font-black uppercase tracking-widest text-slate-500">Protocol</th>
                                  <th className="p-4 text-[10px] font-black uppercase tracking-widest text-slate-500">Status</th>
                                  <th className="p-4 text-[10px] font-black uppercase tracking-widest text-slate-500">Actions</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                              {users.map(user => (
                                  <tr key={user.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors">
                                      <td className="p-4">
                                          <div className="flex items-center gap-3">
                                              <div className="h-10 w-10 rounded-xl bg-slate-200 dark:bg-slate-700 flex items-center justify-center overflow-hidden border border-white/10">
                                                  {user.profilePhoto ? <img src={user.profilePhoto} className="h-full w-full object-cover" /> : <svg className="w-6 h-6 text-slate-400" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd"/></svg>}
                                              </div>
                                              <div>
                                                  <p className="font-black text-slate-900 dark:text-white text-sm leading-tight">{user.name}</p>
                                                  <p className="text-xs text-slate-500">{user.phoneNumber}</p>
                                              </div>
                                          </div>
                                      </td>
                                      <td className="p-4 text-xs font-bold text-slate-600 dark:text-slate-400">{user.role}</td>
                                      <td className="p-4">
                                          <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${user.status === UserStatus.Approved ? 'bg-green-50 text-green-600 dark:bg-green-900/30 dark:text-green-400' : 'bg-yellow-50 text-yellow-600'}`}>
                                              {user.status}
                                          </span>
                                      </td>
                                      <td className="p-4">
                                          <div className="flex gap-2">
                                              {user.status === UserStatus.Pending && <Button variant="success" className="!rounded-xl !py-1.5 !px-3 !text-[10px]" onClick={() => useAppContext().approveUser(user.id)}>Clear</Button>}
                                              <Button variant="danger" className="!rounded-xl !py-1.5 !px-3 !text-[10px]" onClick={() => window.confirm("Request deletion?") && useAppContext().requestDeletion(user.id)}>Revoke</Button>
                                          </div>
                                      </td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </Card>
          </div>
      )}

      {activeView === 'reports' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <Card className="hover:scale-[1.02] transition-transform cursor-pointer border-t-4 border-cyan-500" onClick={() => setIsExportReportModalOpen(true)}>
                  <h3 className="text-xl font-black mb-2">VC Data Archives</h3>
                  <p className="text-sm text-slate-500 mb-4">Compile comprehensive bridge connection metrics into CSV format.</p>
                  <Button variant="secondary" className="w-full !rounded-xl">Access Archives</Button>
              </Card>
              <Card className="hover:scale-[1.02] transition-transform cursor-pointer border-t-4 border-green-500" onClick={() => setIsAttendanceReportModalOpen(true)}>
                  <h3 className="text-xl font-black mb-2">Personnel Analytics</h3>
                  <p className="text-sm text-slate-500 mb-4">Deep dive into attendance frequency and operational readiness reports.</p>
                  <Button variant="secondary" className="w-full !rounded-xl">Open Analytics</Button>
              </Card>
              <Card className="hover:scale-[1.02] transition-transform cursor-pointer border-t-4 border-purple-500" onClick={() => setIsOldVCListOpen(true)}>
                  <h3 className="text-xl font-black mb-2">Historical Logs</h3>
                  <p className="text-sm text-slate-500 mb-4">View legacy connection data from completed or terminated bridges.</p>
                  <Button variant="secondary" className="w-full !rounded-xl">View History</Button>
              </Card>
          </div>
      )}

      {/* Shared Components */}
      <VCDetailsModal vc={selectedVc} onClose={() => setSelectedVc(null)} />
      <EditVCConductorModal vc={vcToEdit} onClose={() => setVcToEdit(null)} />
      <EditVCLocationsModal vc={vcToEditLocations} onClose={() => setVcToEditLocations(null)} />
      <PostponeVCModal vc={vcToPostpone} onClose={() => setVcToPostpone(null)} />
      <EmergencyVCModal isOpen={isEmergencyModalOpen} onClose={() => setIsEmergencyModalOpen(false)} />
      <EmergencyVCListModal isOpen={isEmergencyListOpen} onClose={() => setIsEmergencyListOpen(false)} />
      <ReminderSettingsModal isOpen={isSettingsModalOpen} onClose={() => setIsSettingsModalOpen(false)} user={currentUser} />
      <AttendanceReportModal isOpen={isAttendanceReportModalOpen} onClose={() => setIsAttendanceReportModalOpen(false)} />
      <ExportReportModal isOpen={isExportReportModalOpen} onClose={() => setIsExportReportModalOpen(false)} vcs={vcs} users={users} managerName="Authority" />
      <OldVCListModal isOpen={isOldVCListOpen} onClose={() => setIsOldVCListOpen(false)} vcs={vcs} />
    </div>
  );
};

export default ReportingAuthorityDashboard;

import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAppContext } from '../hooks/useAppContext';
import { VC, VCStatus } from '../types';
import Button from './common/Button';
import Card from './common/Card';
import VCDetailsModal from './VCDetailsModal';
import EmergencyVCModal from './EmergencyVCModal';
import Modal from './common/Modal';
import EmergencyVCListModal from './EmergencyVCListModal';
import ContactSticker from './common/ContactSticker';
import LocationSticker from './common/LocationSticker';
import ReminderSettingsModal from './ReminderSettingsModal';
import UserSticker from './common/UserSticker';
import AttendanceTracker from './AttendanceTracker';
import EditVCLocationsModal from './EditVCLocationsModal';
import CalendarView from './CalendarView';
import PostponeVCModal from './PostponeVCModal';
