const SettingsIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0L8.12 5.12c-.67.21-1.3.54-1.85.98l-1.68-.78c-1.45-.67-3.03.91-2.36 2.36l.78 1.68c-.44.55-.77 1.18-.98 1.85l-1.94.39c-1.56.38-1.56 2.6 0 2.98l1.94.39c.21.67.54 1.3.98 1.85l-.78 1.68c-.67 1.45.91 3.03 2.36 2.36l1.68-.78c.55.44 1.18.77 1.85.98l.39 1.94c.38 1.56 2.6 1.56 2.98 0l.39-1.94c.67-.21 1.3-.54 1.85-.98l1.68.78c1.45.67 3.03-.91 2.36-2.36l-.78-1.68c.44-.55.77-1.18-.98-1.85l1.94-.39c-1.56-.38-1.56-2.6 0-2.98l-1.94-.39c-.21-.67-.54-1.3-.98-1.85l.78-1.68c.67-1.45-.91-3.03-2.36-2.36l-1.68.78c-.55-.44-1.18-.77-1.85-.98L11.49 3.17zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
    </svg>
);

const ConductorDashboard: React.FC = () => {
  const { currentUser, vcs, updateVCStatus, cancelVC } = useAppContext();
  const navigate = useNavigate();
  const [activeView, setActiveView] = useState<'vcs' | 'attendance' | 'reports'>('vcs');
  const [vcViewMode, setVcViewMode] = useState<'list' | 'calendar'>('list');
  const [selectedVc, setSelectedVc] = useState<VC | null>(null);
  const [vcToComplete, setVcToComplete] = useState<VC | null>(null);
  const [vcToEditLocations, setVcToEditLocations] = useState<VC | null>(null);
  const [vcToPostpone, setVcToPostpone] = useState<VC | null>(null);
  const [vcToReport, setVcToReport] = useState<VC | null>(null);
  const [remarks, setRemarks] = useState('');
  const [isEmergencyModalOpen, setIsEmergencyModalOpen] = useState(false);
  const [isEmergencyListOpen, setIsEmergencyListOpen] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);
  const [isAttendanceReportModalOpen, setIsAttendanceReportModalOpen] = useState(false);
  const [isOldVCListOpen, setIsOldVCListOpen] = useState(false);

  const activeConductorVCs = useMemo(() => {
    if (!currentUser) return [];
    return vcs.filter(vc => vc.conductorId === currentUser.id && vc.status !== VCStatus.Completed && vc.status !== VCStatus.Cancelled)
      .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());
  }, [currentUser, vcs]);

  const handleStartVC = (vcId: string) => updateVCStatus(vcId, VCStatus.InProgress);

  const handleCompleteVC = () => {
    if (vcToComplete) {
      updateVCStatus(vcToComplete.id, VCStatus.Completed, remarks);
      setVcToComplete(null);
      setRemarks('');
    }
  };

  const getStatusColor = (status: VCStatus) => {
    switch (status) {
      case VCStatus.Scheduled: return 'bg-blue-50 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400';
      case VCStatus.InProgress: return 'bg-yellow-50 text-yellow-600 dark:bg-yellow-900/30 dark:text-yellow-400';
      case VCStatus.Postponed: return 'bg-purple-50 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400';
      default: return 'bg-slate-50 text-slate-500';
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-900 dark:text-white tracking-tight mb-2">Mission Operations</h2>
          <p className="text-slate-500 dark:text-slate-400 text-sm font-medium uppercase tracking-[0.2em]">Pilot Hub: {currentUser?.name}</p>
        </div>
        <div className="flex flex-wrap gap-2">
            <Button onClick={() => navigate('/salary')} variant="success" className="!rounded-2xl shadow-lg shadow-green-500/10">Salary Portal</Button>
            <Button variant="danger" onClick={() => setIsEmergencyModalOpen(true)} className="!rounded-2xl">Deploy Emergency VC</Button>
            <button onClick={() => setIsSettingsModalOpen(true)} className="p-3 bg-white dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700 text-slate-600 dark:text-slate-400 transition-all">
              <SettingsIcon />
            </button>
        </div>
      </div>

      <RoomUsageSection />

      <div className="flex bg-slate-200/50 dark:bg-slate-800/50 p-1.5 rounded-2xl border border-white/10 w-fit">
        {[
          { id: 'vcs', label: 'My Bridges' },
          { id: 'attendance', label: 'Duty Logs' },
          { id: 'reports', label: 'Summaries' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveView(tab.id as any)}
            className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeView === tab.id ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-md' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {activeView === 'vcs' && (
         <div className="space-y-6">
            <div className="flex justify-between items-center px-2">
                <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Current Assignment Queue</h3>
                <Button variant="secondary" onClick={() => setVcViewMode(vcViewMode === 'list' ? 'calendar' : 'list')} className="!rounded-xl !text-[10px]">
                    {vcViewMode === 'list' ? 'Calendar' : 'Task List'}
                </Button>
            </div>

            {vcViewMode === 'list' ? (
                <div className="grid grid-cols-1 gap-4">
                {activeConductorVCs.length > 0 ? activeConductorVCs.map(vc => (
                    <div key={vc.id} className="group bg-white dark:bg-slate-900/60 p-6 rounded-[2.5rem] border border-slate-100 dark:border-white/5 flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 hover:shadow-xl transition-all duration-500">
                        <div className="flex-1 space-y-3">
                            <div className="flex items-center gap-3">
                                <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${getStatusColor(vc.status)}`}>
                                    {vc.status}
                                </span>
                                <span className="text-xs font-bold text-slate-400 uppercase tracking-tighter">{new Date(vc.startTime).toLocaleString()}</span>
                            </div>
                            <h4 className="text-2xl font-black text-slate-900 dark:text-white group-hover:text-cyan-600 transition-colors">{vc.subject}</h4>
                            <div className="flex flex-wrap items-center gap-3">
                                <ContactSticker label="Authority" userId={vc.reportingAuthorityId} />
                                <LocationSticker locations={vc.locations} />
                                {(vc.status === VCStatus.Scheduled || vc.status === VCStatus.InProgress) && <PauseSticker onClick={() => setVcToPostpone(vc)} className="!rounded-xl" />}
                            </div>
                        </div>
                        <div className="flex flex-wrap gap-2 lg:bg-slate-50 dark:lg:bg-slate-800/40 lg:p-2 lg:rounded-3xl">
                            <Button variant="secondary" onClick={() => setSelectedVc(vc)} className="!rounded-2xl !text-[10px] font-black uppercase">Inspect</Button>
                            <button onClick={() => setVcToReport(vc)} className={`flex items-center gap-1.5 px-4 py-2 rounded-2xl text-[10px] font-black uppercase transition-all ${vc.technicalIssue ? 'bg-green-600 text-white' : 'bg-orange-500/10 text-orange-600'}`}>
                                {vc.technicalIssue ? 'Fixed' : 'Alert'}
                            </button>
                            {vc.status === VCStatus.Scheduled && <Button variant="success" onClick={() => handleStartVC(vc.id)} className="!rounded-2xl !text-[10px] font-black uppercase">Ignite</Button>}
                            {vc.status === VCStatus.InProgress && <Button onClick={() => setVcToComplete(vc)} className="!rounded-2xl !text-[10px] font-black uppercase">Terminal</Button>}
                        </div>
                    </div>
                )) : (
                    <div className="bg-slate-100/50 dark:bg-slate-800/20 rounded-[3rem] p-20 text-center border-2 border-dashed border-slate-200 dark:border-slate-800">
                        <p className="text-slate-400 font-bold uppercase tracking-widest">No active deployments detected</p>
                    </div>
                )}
                </div>
            ) : (
                <CalendarView vcs={activeConductorVCs} />
            )}
         </div>
      )}

      {activeView === 'attendance' && currentUser && <AttendanceTracker conductorId={currentUser.id} />}

      {activeView === 'reports' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Card className="hover:scale-[1.02] transition-transform border-t-4 border-cyan-500">
                <h3 className="text-xl font-black mb-2">Bridge History</h3>
                <p className="text-sm text-slate-500 mb-6">Review all historical VC bridge data associated with your protocol.</p>
                <Button variant="secondary" onClick={() => setIsOldVCListOpen(true)} className="w-full !rounded-xl">Access Logs</Button>
            </Card>
            <Card className="hover:scale-[1.02] transition-transform border-t-4 border-green-500">
                <h3 className="text-xl font-black mb-2">Duty Analytics</h3>
                <p className="text-sm text-slate-500 mb-6">Generate official attendance and performance metrics reports.</p>
                <Button variant="secondary" onClick={() => setIsAttendanceReportModalOpen(true)} className="w-full !rounded-xl">Open Reports</Button>
            </Card>
        </div>
      )}

      <VCDetailsModal vc={selectedVc} onClose={() => setSelectedVc(null)} />
      <EditVCLocationsModal vc={vcToEditLocations} onClose={() => setVcToEditLocations(null)} />
      <PostponeVCModal vc={vcToPostpone} onClose={() => setVcToPostpone(null)} />
      <EmergencyVCModal isOpen={isEmergencyModalOpen} onClose={() => setIsEmergencyModalOpen(false)} />
      <EmergencyVCListModal isOpen={isEmergencyListOpen} onClose={() => setIsEmergencyListOpen(false)} />
      <ReminderSettingsModal isOpen={isSettingsModalOpen} onClose={() => setIsSettingsModalOpen(false)} user={currentUser} />
      <AttendanceReportModal isOpen={isAttendanceReportModalOpen} onClose={() => setIsAttendanceReportModalOpen(false)} />
      <ReportIssueModal vc={vcToReport} onClose={() => setVcToReport(null)} />
      <OldVCListModal isOpen={isOldVCListOpen} onClose={() => setIsOldVCListOpen(false)} vcs={vcs.filter(v => v.conductorId === currentUser?.id)} />

      <Modal isOpen={!!vcToComplete} onClose={() => setVcToComplete(null)} title="Mission Debrief">
        <div className="space-y-4">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Post-Bridge Remarks</label>
          <textarea
            value={remarks}
            onChange={(e) => setRemarks(e.target.value)}
            rows={4}
            className="w-full p-4 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white border-2 border-slate-100 dark:border-slate-800 rounded-2xl focus:border-cyan-500 outline-none"
            placeholder="Document any technical notes or anomalies..."
          />
        </div>
        <div className="flex justify-end gap-3 mt-8">
          <Button variant="secondary" onClick={() => setVcToComplete(null)}>Standby</Button>
          <Button onClick={handleCompleteVC}>Finalize Connection</Button>
        </div>
      </Modal>
    </div>
  );
};

export default ConductorDashboard;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useAppContext } from '../hooks/useAppContext';
import { VC, VCStatus } from '../types';
import Button from './common/Button';
import Card from './common/Card';
import VCDetailsModal from './VCDetailsModal';
import EmergencyVCListModal from './EmergencyVCListModal';
import ContactSticker from './common/ContactSticker';
import LocationSticker from './common/LocationSticker';
import ReminderSettingsModal from './ReminderSettingsModal';
import UserSticker from './common/UserSticker';
import CalendarView from './CalendarView';
import EditRoomDetailsModal from './EditRoomDetailsModal';
import { useNavigate } from 'react-router-dom';
import RoomUsageSection from './RoomUsageSection';
import { PREDEFINED_ROOMS } from '../constants';

const SettingsIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0L8.12 5.12c-.67.21-1.3.54-1.85.98l-1.68-.78c-1.45-.67-3.03.91-2.36 2.36l.78 1.68c-.44.55-.77 1.18-.98 1.85l-1.94.39c-1.56.38-1.56 2.6 0 2.98l1.94.39c.21.67.54 1.3.98 1.85l-.78 1.68c-.67 1.45.91 3.03 2.36 2.36l1.68-.78c.55.44 1.18.77 1.85.98l.39 1.94c.38 1.56 2.6 1.56 2.98 0l.39-1.94c.67-.21 1.3-.54 1.85-.98l1.68.78c1.45.67 3.03-.91 2.36-2.36l-.78-1.68c.44-.55.77-1.18-.98-1.85l1.94-.39c-1.56-.38-1.56-2.6 0-2.98l-1.94-.39c-.21-.67-.54-1.3-.98-1.85l.78-1.68c.67-1.45-.91-3.03-2.36-2.36l-1.68.78c-.55-.44-1.18-.77-1.85-.98L11.49 3.17zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
    </svg>
);

const RailTelDashboard: React.FC = () => {
  const { currentUser, vcs } = useAppContext();
  const navigate = useNavigate();

  const [selectedVc, setSelectedVc] = useState<VC | null>(null);
  const [vcToEditRoom, setVcToEditRoom] = useState<VC | null>(null);
  const [isEmergencyListOpen, setIsEmergencyListOpen] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);
  const [activeView, setActiveView] = useState<'monitor' | 'rooms' | 'details'>('monitor');
  const [vcViewMode, setVcViewMode] = useState<'list' | 'calendar'>('list');
  const [highlightedRoomIp, setHighlightedRoomIp] = useState<string | null>(null);

  const prevInProgressIdsRef = useRef<Set<string>>(new Set());

  const allVCs = useMemo(() => {
    const predefinedNames = PREDEFINED_ROOMS.map(r => r.name);
    return [...vcs]
      .filter(vc => vc.locations.some(loc => predefinedNames.includes(loc)))
      .sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());
  }, [vcs]);

  useEffect(() => {
    const currentInProgressIds = new Set(allVCs.filter(vc => vc.status === VCStatus.InProgress).map(vc => vc.id));
    currentInProgressIds.forEach(id => {
        if (!prevInProgressIdsRef.current.has(id)) {
            const meeting = allVCs.find(v => v.id === id);
            if (meeting) alert(`⚠️ NETWORK ALERT: Meeting Live\nSubject: ${meeting.subject}\nNode: ${meeting.roomIp || 'N/A'}`);
        }
    });
    prevInProgressIdsRef.current = currentInProgressIds;
  }, [allVCs]);

  const handleRoomClickFromRealtimeStatus = (roomIp: string) => {
      setActiveView('rooms');
      setHighlightedRoomIp(roomIp);
      setTimeout(() => {
          const el = document.getElementById(`room-card-${roomIp}`);
          if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 100);
      setTimeout(() => setHighlightedRoomIp(null), 3000);
  };

  const getStatusColor = (status: VCStatus) => {
    switch (status) {
      case VCStatus.Scheduled: return 'bg-blue-500 text-white';
      case VCStatus.InProgress: return 'bg-red-500 text-white animate-pulse';
      case VCStatus.Completed: return 'bg-green-500 text-white';
      case VCStatus.Postponed: return 'bg-purple-500 text-white';
      default: return 'bg-slate-500 text-white';
    }
  };

  return (
    <div className="space-y-8 animate-fade-in font-mono">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter mb-2">Network Control</h2>
          <div className="flex items-center gap-4">
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em]">System Entropy: Stable</span>
            <span className="h-1.5 w-1.5 rounded-full bg-cyan-500 shadow-[0_0_10px_#22d3ee]"></span>
          </div>
        </div>
        <div className="flex gap-2">
            <Button onClick={() => setIsEmergencyListOpen(true)} variant="secondary" className="!rounded-xl border-slate-200">Alert History</Button>
            <button onClick={() => setIsSettingsModalOpen(true)} className="p-3 bg-white dark:bg-slate-800 rounded-xl border border-slate-100 dark:border-slate-700 text-slate-600 transition-all hover:bg-slate-50">
              <SettingsIcon />
            </button>
        </div>
      </div>

      <RoomUsageSection onRoomClick={handleRoomClickFromRealtimeStatus} />

      <div className="flex bg-slate-900/10 dark:bg-slate-800/50 p-1.5 rounded-xl border border-slate-200 dark:border-white/5 w-fit">
        {[
          { id: 'monitor', label: 'Telemetry' },
          { id: 'rooms', label: 'Nodes' },
          { id: 'details', label: 'Configs' }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveView(tab.id as any)}
            className={`px-6 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeView === tab.id ? 'bg-slate-900 dark:bg-slate-700 text-white shadow-lg' : 'text-slate-500'}`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {activeView === 'monitor' && (
        <div className="space-y-6">
            <div className="flex justify-between items-center px-2">
                <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Active Data Streams</h3>
                <Button variant="ghost" onClick={() => setVcViewMode(vcViewMode === 'list' ? 'calendar' : 'list')} className="!text-[10px]">
                    Switch To {vcViewMode === 'list' ? 'Matrix' : 'List'}
                </Button>
            </div>

            {vcViewMode === 'list' ? (
                <div className="grid grid-cols-1 gap-3">
                {allVCs.map(vc => (
                    <div key={vc.id} className={`bg-white dark:bg-slate-900 p-4 rounded-2xl border transition-all duration-300 ${vc.technicalIssue ? 'border-red-500 shadow-lg shadow-red-500/10' : 'border-slate-100 dark:border-white/5'}`}>
                        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
                            <div className="space-y-2">
                                <div className="flex items-center gap-3">
                                    <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-tighter ${getStatusColor(vc.status)}`}>{vc.status}</span>
                                    <span className="text-[10px] text-slate-400 font-mono">[{vc.roomIp || 'NO_IP'}]</span>
                                </div>
                                <h4 className="text-lg font-black text-slate-900 dark:text-white uppercase tracking-tighter">{vc.subject}</h4>
                            </div>
                            <div className="flex gap-2">
                                {vc.technicalIssue && <span className="bg-red-600 text-white text-[8px] font-black px-2 py-1 rounded animate-pulse uppercase tracking-widest">Signal Failure</span>}
                                <Button variant="secondary" onClick={() => setSelectedVc(vc)} className="!rounded-xl !py-1 !px-4 !text-[8px] font-black uppercase">Inspect Data</Button>
                            </div>
                        </div>
                    </div>
                ))}
                </div>
            ) : (
                <CalendarView vcs={allVCs} />
            )}
        </div>
      )}

      {activeView === 'rooms' && (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
               {allVCs.map(vc => (
                   <div key={vc.id} id={`room-card-${vc.roomIp}`} onClick={() => setSelectedVc(vc)} className={`p-5 rounded-[2rem] border transition-all cursor-pointer ${highlightedRoomIp === vc.roomIp ? 'border-cyan-500 shadow-xl scale-[1.02]' : 'bg-white dark:bg-slate-900 border-slate-100 dark:border-white/5'}`}>
                        <p className="text-[8px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">Terminal: {vc.roomName || 'GENERIC'}</p>
                        <h4 className="text-lg font-black mb-4 truncate text-slate-900 dark:text-white tracking-tighter">{vc.subject}</h4>
                        <div className="flex flex-col gap-2">
                            <span className="text-[10px] bg-slate-100 dark:bg-slate-800 p-2 rounded-xl font-mono text-center">{vc.roomIp}</span>
                            <div className="flex justify-between items-center mt-2">
                                <span className={`h-2 w-2 rounded-full ${vc.status === VCStatus.InProgress ? 'bg-red-500 animate-ping' : 'bg-slate-300'}`}></span>
                                <span className="text-[10px] font-black text-slate-500">{vc.status}</span>
                            </div>
                        </div>
                   </div>
               ))}
           </div>
      )}

      {activeView === 'details' && (
          <Card className="!p-0 border-0 overflow-hidden bg-slate-900 text-cyan-500">
              <div className="overflow-x-auto">
                  <table className="w-full text-left text-xs">
                      <thead className="bg-slate-950 border-b border-white/10">
                          <tr>
                              <th className="p-4 uppercase tracking-[0.2em]">Node Identifier</th>
                              <th className="p-4 uppercase tracking-[0.2em]">Assigned IP</th>
                              <th className="p-4 uppercase tracking-[0.2em]">Protocol Zone</th>
                              <th className="p-4 text-center uppercase tracking-[0.2em]">Ops</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-white/5 font-mono">
                          {allVCs.map(vc => (
                              <tr key={vc.id} className="hover:bg-cyan-500/5 transition-colors">
                                  <td className="p-4 text-white font-black">{vc.subject}</td>
                                  <td className="p-4 opacity-70">{vc.roomIp}</td>
                                  <td className="p-4 opacity-70">{vc.buildingType || 'CORE'}</td>
                                  <td className="p-4 text-center">
                                      <button onClick={() => setVcToEditRoom(vc)} className="text-white hover:text-cyan-400 transition-colors uppercase font-black text-[10px] tracking-widest border border-white/20 px-3 py-1 rounded">Adjust</button>
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </Card>
      )}

      <VCDetailsModal vc={selectedVc} onClose={() => setSelectedVc(null)} />
      <EditRoomDetailsModal vc={vcToEditRoom} onClose={() => setVcToEditRoom(null)} />
      <EmergencyVCListModal isOpen={isEmergencyListOpen} onClose={() => setIsEmergencyListOpen(false)} />
      <ReminderSettingsModal isOpen={isSettingsModalOpen} onClose={() => setIsSettingsModalOpen(false)} user={currentUser} />
    </div>
  );
};

export default RailTelDashboard;

import React, { ReactNode } from 'react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: ReactNode;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 bg-slate-950/80 flex justify-center items-center z-[60] backdrop-blur-xl animate-fade-in"
      onClick={onClose}
    >
      <div
        className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-white/10 rounded-[2.5rem] shadow-[0_32px_64px_rgba(0,0,0,0.4)] w-11/12 md:w-3/4 lg:w-1/2 max-w-2xl p-8 md:p-10 transition-all duration-300 animate-slide-up overflow-hidden relative"
        onClick={e => e.stopPropagation()}
      >
        <div className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-3xl font-black text-slate-900 dark:text-white tracking-tighter leading-tight">{title}</h2>
            <div className="h-1 w-12 bg-cyan-500 mt-2 rounded-full"></div>
          </div>
          <button 
            onClick={onClose} 
            className="p-3 bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-slate-900 dark:hover:text-white rounded-2xl transition-all hover:scale-110"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>
        <div className="relative z-10">{children}</div>
      </div>

      <style>{`
        @keyframes slideUp {
          from { opacity: 0; transform: translateY(20px) scale(0.98); }
          to { opacity: 1; transform: translateY(0) scale(1); }
        }
        .animate-slide-up {
          animation: slideUp 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
      `}</style>
    </div>
  );
};

export default Modal;
